            }
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
}

struct PromptSanitiser {
    static func sanitise(_ userInput: String) -> String {
        // Trim leading/trailing whitespace.
        var clean = userInput.trimmingCharacters(in: .whitespacesAndNewlines)
        // Collapse repeated whitespace.
        clean = clean.replacingOccurrences(
            of: #"\s{2,}"#,
            with: " ",
            options: .regularExpression
        )
        // Enforce a max character count to limit runaway input.
        let maxChars = 2000
        if clean.count > maxChars {
            clean = String(clean.prefix(maxChars))
        }
        return clean
    }
}

