// iOS client: sends prompt to YOUR backend, not directly to Anthropic.
struct ClaudeProxyClient {
    private let baseURL = URL(string: "https://api.yourapp.com/ai")!

    func send(userMessage: String, systemPrompt: String) async throws -> String {
        var request = URLRequest(url: baseURL.appending(path: "message"))
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        // Authenticate the request with the user's app session token, not the Anthropic key.
        request.setValue("Bearer \(SessionToken.current)", forHTTPHeaderField: "Authorization")

        let body = [
            "user_message": userMessage,
            "system": systemPrompt
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)

        let (data, response) = try await URLSession.shared.data(for: request)
        guard (response as? HTTPURLResponse)?.statusCode == 200 else {
            throw ClaudeError.serverError
        }
        // Decode the text returned by your backend.
        struct Reply: Decodable { let text: String }
        return try JSONDecoder().decode(Reply.self, from: data).text
    }
}

struct ContentFilter {
    // These are illustrative — adapt to your domain.
    private static let blockedPhrases: Set<String> = [
        "step-by-step instructions for",
        "how to make explosives"
    ]

    static func isAcceptable(_ text: String) -> Bool {
        let lower = text.lowercased()
        for phrase in blockedPhrases {
            if lower.contains(phrase) { return false }
        }
        return true
    }
}

// Usage in view model:
func handleClaudeResponse(_ text: String) {
    if ContentFilter.isAcceptable(text) {
        displayedResponse = text
    } else {
        displayedResponse = "I cannot provide that information."
        reportFilterTrigger(text) // log to your backend
    }
}
